class Solution {
public:
    int numberOfWays(int n, int x) {
        vector<int> dp(n + 1, 0);
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= i; j++) {
                if (j * pow(j, x) <= i) {
                    dp[i] = (dp[i] + dp[i - j * pow(j, x)]) % 1000000007;
                }
            }
        }
        return dp[n];
    }
};
